import{c as i,Q as o,j as a,m as l}from"./chunks/framework.j5cTrcw1.js";const u=JSON.parse('{"title":"项目整理与入侵痕迹检查记录","description":"","frontmatter":{},"headers":[],"relativePath":"project-security-check-2026-06-13.md","filePath":"project-security-check-2026-06-13.md"}'),t={name:"project-security-check-2026-06-13.md"};function d(c,e,s,n,r,h){return o(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="项目整理与入侵痕迹检查记录" tabindex="-1">项目整理与入侵痕迹检查记录 <a class="header-anchor" href="#项目整理与入侵痕迹检查记录" aria-label="Permalink to &quot;项目整理与入侵痕迹检查记录&quot;">​</a></h1><p>检查时间：2026-06-13</p><h2 id="检查范围" tabindex="-1">检查范围 <a class="header-anchor" href="#检查范围" aria-label="Permalink to &quot;检查范围&quot;">​</a></h2><ul><li>Git 工作区、最近提交、远程仓库配置。</li><li>Git hooks、GitHub Actions 工作流、发布脚本、安装脚本。</li><li>近三天内变更文件。</li><li>常见入侵痕迹关键字：硬编码 token、私钥、反连命令、<code>eval</code>、Base64 解码执行、<code>authorized_keys</code>、<code>curl | bash</code>、旧授权端、旧仓库链接等。</li><li>前端依赖审计与 Go 依赖版本检查。</li><li>Git 对象完整性检查。</li></ul><h2 id="当前项目状态" tabindex="-1">当前项目状态 <a class="header-anchor" href="#当前项目状态" aria-label="Permalink to &quot;当前项目状态&quot;">​</a></h2><ul><li>当前分支：<code>main</code></li><li>当前远程： <ul><li><code>origin</code> -&gt; <code>https://github.com/iKeilo/FLVXR2.git</code></li><li><code>flvxr2</code> -&gt; <code>https://github.com/iKeilo/FLVXR2.git</code></li><li><code>old-origin</code> -&gt; <code>https://github.com/iKeilo/flvxt2.git</code></li></ul></li><li>最近提交：<code>0fa2d8f7 Add sidebar panel update entry</code></li><li>当前存在未提交改动，主要集中在限速规则、用户限速、隧道限速、规则绑定相关文件。</li><li>当前存在未跟踪文档：<code>docs/speed-limit-scope-design.md</code></li></ul><h2 id="未发现的高危入侵迹象" tabindex="-1">未发现的高危入侵迹象 <a class="header-anchor" href="#未发现的高危入侵迹象" aria-label="Permalink to &quot;未发现的高危入侵迹象&quot;">​</a></h2><p>本轮检查未发现以下典型入侵痕迹：</p><ul><li>未发现启用的恶意 Git hook，<code>.git/hooks</code> 下只有默认 <code>.sample</code> 文件。</li><li>未发现硬编码 GitHub token、AWS key、Slack token、私钥文件等高风险凭据。</li><li>未发现 <code>/dev/tcp</code>、<code>nc -e</code>、<code>ncat -e</code>、<code>authorized_keys</code> 写入等反连或持久化痕迹。</li><li>未发现异常 <code>eval</code>、<code>new Function</code>、<code>FromBase64String</code>、<code>base64 -d</code> 后执行代码的模式。</li><li>未发现 <code>LICENSE_SERVER_URL=https://sq.abai.eu.org</code> 残留。</li><li><code>git fsck --full --no-reflogs</code> 未报告对象损坏，只报告了 dangling commit/blob，这通常来自 rebase、reset、临时提交或历史操作，不等于入侵。</li></ul><h2 id="需要整理的残留项" tabindex="-1">需要整理的残留项 <a class="header-anchor" href="#需要整理的残留项" aria-label="Permalink to &quot;需要整理的残留项&quot;">​</a></h2><h3 id="_1-旧远程仍保留" tabindex="-1">1. 旧远程仍保留 <a class="header-anchor" href="#_1-旧远程仍保留" aria-label="Permalink to &quot;1. 旧远程仍保留&quot;">​</a></h3><p><code>.git/config</code> 中仍存在：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>old-origin -&gt; https://github.com/iKeilo/flvxt2.git</span></span></code></pre></div><p>这不是入侵痕迹，但后续发布时容易误推或误拉旧项目。建议确认不再需要后执行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remote</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remove</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> old-origin</span></span></code></pre></div><h3 id="_2-文档构建产物仍有旧仓库链接" tabindex="-1">2. 文档构建产物仍有旧仓库链接 <a class="header-anchor" href="#_2-文档构建产物仍有旧仓库链接" aria-label="Permalink to &quot;2. 文档构建产物仍有旧仓库链接&quot;">​</a></h3><p>扫描到以下旧链接残留：</p><ul><li><code>docs/.vitepress/config.ts</code> 仍指向 <code>https://github.com/iKeilo/flvxt2</code></li><li><code>docs/assets/*.js</code> 中仍有旧 <code>iKeilo/flvxt2</code> 的构建产物</li><li><code>landing/doc/install.md</code> 中仍有 <code>Sagit-chu/flux-panel</code></li><li><code>landing/doc/ai-skill.md</code> 中仍有 <code>Sagit-chu/flvx</code></li></ul><p>这些更像历史文档/上游兼容说明残留，不像被植入。若要彻底品牌独立，建议统一替换为 <code>iKeilo/FLVXR2</code>，并重新构建 docs/landing。</p><h3 id="_3-仍有兼容旧项目的协议命名" tabindex="-1">3. 仍有兼容旧项目的协议命名 <a class="header-anchor" href="#_3-仍有兼容旧项目的协议命名" aria-label="Permalink to &quot;3. 仍有兼容旧项目的协议命名&quot;">​</a></h3><p>代码中存在 <code>flvxt2-v1</code>、<code>Sagit-chu compatible</code>，主要出现在面板共享兼容逻辑中。这个属于之前设计的兼容行为，不是入侵痕迹。</p><h3 id="_4-发布辅助脚本中仍有国内同步脚本" tabindex="-1">4. 发布辅助脚本中仍有国内同步脚本 <a class="header-anchor" href="#_4-发布辅助脚本中仍有国内同步脚本" aria-label="Permalink to &quot;4. 发布辅助脚本中仍有国内同步脚本&quot;">​</a></h3><p><code>scripts/sync-gost-to-domestic.sh</code> 仍存在。当前主安装脚本已经走 GitHub，但如果后续策略是完全取消国内加速，可以考虑删除或改为归档说明，避免误用。</p><h2 id="安装与升级脚本检查" tabindex="-1">安装与升级脚本检查 <a class="header-anchor" href="#安装与升级脚本检查" aria-label="Permalink to &quot;安装与升级脚本检查&quot;">​</a></h2><p>主脚本当前关键仓库指向正常：</p><ul><li><code>install.sh</code>：<code>REPO=&quot;iKeilo/FLVXR2&quot;</code></li><li><code>panel_install.sh</code>：<code>REPO=&quot;iKeilo/FLVXR2&quot;</code></li><li>Docker 镜像：<code>ghcr.io/ikeilo/flvxr2-svc-backend</code>、<code>ghcr.io/ikeilo/flvxr2-svc-frontend</code></li><li>后端升级逻辑：下载 <code>https://raw.githubusercontent.com/iKeilo/FLVXR2/main/panel_install.sh</code></li></ul><p><code>panel_install.sh</code> 会删除 <code>.env</code> 中的 <code>LICENSE_SERVER_URL</code>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sed</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;/^LICENSE_SERVER_URL=/d&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;.env&quot;</span></span></code></pre></div><p>后端 <code>env_writer.go</code> 也会移除 <code>LICENSE_SERVER_URL</code> 行。</p><h2 id="依赖检查" tabindex="-1">依赖检查 <a class="header-anchor" href="#依赖检查" aria-label="Permalink to &quot;依赖检查&quot;">​</a></h2><h3 id="前端-npm-audit" tabindex="-1">前端 npm audit <a class="header-anchor" href="#前端-npm-audit" aria-label="Permalink to &quot;前端 npm audit&quot;">​</a></h3><p><code>npm audit --audit-level=high --omit=dev</code> 返回 3 个 moderate 级别问题：</p><ul><li><code>postcss &lt; 8.5.10</code></li><li><code>react-router / react-router-dom &lt;= 6.30.3</code></li></ul><p>这些不是入侵痕迹，但属于依赖安全维护项。建议后续单独升级并回归测试。</p><h3 id="go-依赖" tabindex="-1">Go 依赖 <a class="header-anchor" href="#go-依赖" aria-label="Permalink to &quot;Go 依赖&quot;">​</a></h3><p><code>go list -m -u all</code> 显示若干依赖有新版本，例如：</p><ul><li><code>golang.org/x/crypto</code></li><li><code>golang.org/x/net</code></li><li><code>golang.org/x/sys</code></li><li><code>modernc.org/sqlite</code></li><li><code>github.com/jackc/pgx/v5</code></li></ul><p>本轮未发现明显异常来源依赖。是否升级建议单独开任务处理，避免影响 SQLite/PostgreSQL 兼容性。</p><h2 id="本轮结论" tabindex="-1">本轮结论 <a class="header-anchor" href="#本轮结论" aria-label="Permalink to &quot;本轮结论&quot;">​</a></h2><p>当前项目没有发现明确被入侵或被植入后门的证据。</p><p>更像是项目长期迁移、合并和发布过程中留下的整理问题：</p><ul><li>旧远程仍存在。</li><li>文档和 landing 构建产物有旧仓库链接。</li><li>发布脚本目录保留了国内同步脚本。</li><li>依赖存在中等级别安全更新需求。</li><li>当前有大量未提交功能改动，应在继续发布前先完成测试、修复旧契约测试或明确跳过原因，然后提交。</li></ul><h2 id="建议下一步" tabindex="-1">建议下一步 <a class="header-anchor" href="#建议下一步" aria-label="Permalink to &quot;建议下一步&quot;">​</a></h2><ol><li>删除不再需要的 <code>old-origin</code> 远程。</li><li>统一 docs/landing 中的旧项目链接并重新构建文档。</li><li>决定是否删除或归档 <code>scripts/sync-gost-to-domestic.sh</code>。</li><li>修正 <code>/forward/list</code> 旧契约测试，使其读取当前分页结构 <code>data.items</code>。</li><li>单独升级 <code>postcss</code>、<code>react-router-dom</code>，并跑前端构建与核心页面回归。</li><li>在发布前提交当前限速功能改动，避免工作区长期处于混杂状态。</li></ol>',44)])])}const g=i(t,[["render",d]]);export{u as __pageData,g as default};
